    console.error('GitHub API error:', e.message);
    return [];
  }
}

function rankProjectsByRelevance(repos, jobDescription) {
  return repos.map(repo => {
    const relevanceScore = calculateRelevance(
      (repo.description || '') + ' ' + (repo.topics || []).join(' '),
      jobDescription
    );
    return {
      name: repo.name,
      description: repo.description,
      stars: repo.stargazers_count,
      language: repo.language,
      url: repo.html_url,
      relevanceScore: relevanceScore
    };
  })
  .sort((a, b) => b.relevanceScore - a.relevanceScore)
  .slice(0, 5);
}

function calculateRelevance(repoText, jobDescription) {
  const jobKeywords = jobDescription.toLowerCase().split(/\s+/);
  const repoText_lower = repoText.toLowerCase();
  let score = 0;
  jobKeywords.forEach(keyword => {
    if (repoText_lower.includes(keyword)) score += 1;
  });
  return score;
}

