const owner = 'odeliyach';
const repo = 'job-search-data';
const apiBase = 'https://api.github.com';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json'
};

async function apiRequest(method, path, body) {
  return await $helpers.httpRequest({
    method: method,
    url: apiBase + path,
    headers: headers,
    body: body,
  });
}

// Auto-create folder by adding .gitkeep if missing
async function ensureFolderExists(treeItems, folderPath) {
  treeItems.push({
    path: 'Obsidian_Vault/' + folderPath + '/.gitkeep',
    mode: '100644',
    type: 'blob',
    content: ''
  });
}

// Determine target folder based on application status
function getStatusFolder(status) {
  const folderMap = {
    'applied': 'Active',
    'phone_screen_scheduled': 'Waiting',
    'technical_scheduled': 'Waiting',
    'final_round_scheduled': 'Waiting',
    'offer_received': 'Offers',
    'rejected': 'Rejected'
  };
  return folderMap[status] || 'Active';
}

try {
