    'follow_up_day7: ' + (jobData.applied_date || today) + '\n' +
    '---\n\n' +
    '# ' + jobData.company_name + ' - ' + jobData.job_title + '\n\n' +
    '## Job Requirements vs My Skills\n\n' +
    '### Requirements\n' + (jobData.job_requirements || '') + '\n\n' +
    '### My Skills Match\n' + (jobData.user_skills || '') + '\n\n' +
    '## Generated Materials\n\n' +
    '### Resume\n' + (jobData.resume_content || '') + '\n\n' +
    '### Cover Letter\n' + (jobData.cover_letter_content || '') + '\n\n' +
    '### Cold Email\n' + (jobData.cold_email_content || '') + '\n\n' +
    '### Interview Prep\n' + (jobData.interview_prep_content || '') + '\n\n' +
    '### Portfolio Matching\n' + (jobData.portfolio_content || '') + '\n\n' +
    '## Communication Log\n\n' +
    '- **' + today + '** | Applied | Submitted application\n\n' +
    '## Follow-up Schedule\n\n' +
    '- [ ] Day 3 (' + (jobData.applied_date || today) + ' + 3 days): First follow-up\n' +
    '- [ ] Day 7 (' + (jobData.applied_date || today) + ' + 7 days): Second follow-up\n' +
    '- [ ] Post-phone screen: Thank you email\n' +
    '- [ ] Post-technical: Thank you email\n\n' +
    '## Personal Notes\n\n' +
    '_Add your notes here after each interaction_\n';

  filesToCommit.push({
    path: appFolderPath + '/' + companySlug + '.md',
    mode: '100644',
    type: 'blob',
    content: companyFileContent
  });

  // ---- Resume Version File ----
  const resumeVersionHash = Date.now().toString(36);
  const resumeVersionContent = '# Resume Version - ' + jobData.company_name + '\n\n' +
    '**Date:** ' + today + '\n' +
    '**Job:** ' + jobData.job_title + ' at ' + jobData.company_name + '\n' +
    '**Version:** ' + resumeVersionHash + '\n\n' +
    (jobData.resume_content || '') + '\n';

  filesToCommit.push({
    path: resumeVersionPath + '/' + companySlug + '_resume_' + resumeVersionHash + '.md',
    mode: '100644',
    type: 'blob',
    content: resumeVersionContent
  });

  // ---- Interview Prep File ----
  const interviewContent = '# Interview Prep - ' + jobData.company_name + '\n\n' +
    '**Role:** ' + jobData.job_title + '\n' +
    '**Prepared:** ' + today + '\n\n' +
    (jobData.interview_prep_content || '') + '\n';

  filesToCommit.push({
    path: interviewPrepPath + '/' + companySlug + '_interview.md',
    mode: '100644',
    type: 'blob',
    content: interviewContent
  });

  // ---- Legacy files for backward compatibility ----
  const legacyContentMap = {
    'metadata.md': jobData.metadata_content,
    'cold_email.md': jobData.cold_email_content,
    'company_research.md': jobData.company_research_content,
    'personal_angle.md': jobData.personal_angle_content,
    'portfolio_matching.md': jobData.portfolio_content,
    'tracking.md': jobData.tracking_content
  };

  for (const [fileName, content] of Object.entries(legacyContentMap)) {
    if (!content) continue;
    const repoPath = (jobData.year || new Date().getFullYear()) + '/' +
      (jobData.month || (new Date().getMonth() + 1).toString().padStart(2, '0')) + '/' +
      (jobData.folder_name || companySlug) + '/' + fileName;
    filesToCommit.push({ path: repoPath, mode: '100644', type: 'blob', content: content });
  }

  if (jobData.analytics_content) {
    filesToCommit.push({ path: 'analytics.md', mode: '100644', type: 'blob', content: jobData.analytics_content });
  }

  if (filesToCommit.length === 0) {
    return [{
      json: {
        ...jobData,
        git_status: 'skipped',
        git_note: 'No content to commit'
      }
    }];
  }

  // Create blobs and build tree entries
  const treeEntries = [];
  for (const file of filesToCommit) {
    try {
      if (file.sha) {
        treeEntries.push({ path: file.path, mode: file.mode, type: file.type, sha: file.sha });
      } else {
        const blobData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/blobs', {
          content: Buffer.from(file.content || '').toString('base64'),
          encoding: 'base64'
        });
        treeEntries.push({ path: file.path, mode: file.mode, type: file.type, sha: blobData.sha });
      }
    } catch(e) {
      console.error('Error processing file ' + file.path + ':', e.message);
    }
  }

  const newTreeData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/trees', {
    base_tree: treeSha,
    tree: treeEntries
  });

  const commitMessage = 'Job application: ' + jobData.company_name + ' - ' + jobData.job_title + ' - ' + (jobData.applied_date || today);
  const newCommitData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/commits', {
    message: commitMessage,
    tree: newTreeData.sha,
    parents: [currentSha],
    author: {
      name: 'Odeliya Charitonova',
      email: 'odaliya12@gmail.com',
      date: new Date().toISOString()
    }
  });

  await apiRequest('PATCH', '/repos/' + owner + '/' + repo + '/git/refs/heads/main', {
    sha: newCommitData.sha,
    force: false
  });

  return [{
    json: {
      ...jobData,
      git_status: 'success',
      commit_sha: newCommitData.sha,
      obsidian_path: appFolderPath,
      resume_version_path: resumeVersionPath,
      interview_prep_path: interviewPrepPath
    }
  }];

} catch(e) {
  console.error('Git commit failed:', e.message);
  return [{
    json: {
      ...jobData,
      git_status: 'error',
      git_error: e.message
    }
  }];
}

const jobData = $input.item.json;

// ATS keyword scanning and optimization
const jobDescription = jobData.job_description || '';
const jobRequirements = jobData.job_requirements || '';
const fullJobText = jobDescription + ' ' + jobRequirements;

// Common technical keywords to check
const techKeywords = {
  cloud: ['aws', 'gcp', 'azure', 'ec2', 's3', 'lambda', 'rds', 'vpc', 'compute engine', 'cloud run', 'firestore'],
  containerization: ['docker', 'kubernetes', 'k8s', 'helm', 'container', 'orchestration'],
  cicd: ['github actions', 'gitlab ci', 'jenkins', 'circleci', 'ci/cd', 'deployment pipeline'],
  architecture: ['microservices', 'distributed systems', 'scalability', 'system design', 'rest api', 'graphql'],
  databases: ['sql', 'nosql', 'redis', 'postgresql', 'mysql', 'mongodb', 'elasticsearch'],
  testing: ['jest', 'vitest', 'cypress', 'playwright', 'unit test', 'integration test', 'e2e'],
  languages: ['typescript', 'javascript', 'python', 'java', 'go', 'rust', 'node.js', 'react', 'vue', 'angular'],
  devops: ['terraform', 'ansible', 'monitoring', 'observability', 'elk stack', 'datadog', 'prometheus']
};

const fullJobTextLower = fullJobText.toLowerCase();
const foundKeywords = [];
const missingKeywords = [];

for (const [category, keywords] of Object.entries(techKeywords)) {
  for (const keyword of keywords) {
    if (fullJobTextLower.includes(keyword.toLowerCase())) {
      foundKeywords.push({ keyword, category });
    }
  }
}

// Extract all keywords from job description using simple word frequency
const words = fullJobTextLower.split(/\W+/).filter(w => w.length > 3);
const wordFreq = {};
words.forEach(w => { wordFreq[w] = (wordFreq[w] || 0) + 1; });
const topWords = Object.entries(wordFreq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 20)
  .map(([word]) => word);

return [{
  json: {
    ...jobData,
    ats_found_keywords: foundKeywords,
    ats_top_job_keywords: topWords,
    ats_keyword_count: foundKeywords.length,
    ats_status: 'complete'
  }
}];
